  1	import * as React from 'react';
  2	import {
  3	  FormGroup,
  4	  FormHelperText,
  5	  HelperText,
  6	  HelperTextItem,
  7	} from '@patternfly/react-core';
  8	import cx from 'classnames';
  9	import { useField, useFormikContext, FormikValues } from 'formik';
 10	import * as fuzzy from 'fuzzysearch';
 11	import * as _ from 'lodash';
 12	import { useTranslation } from 'react-i18next';
 13	import MultipleKeySelector from './MultipleKeySelector';
 14	import {
 15	  K8sKind,
 16	  K8sResourceKind,
 17	  RedExclamationCircleIcon,
 18	  useActiveNamespace,
 19	  useK8sWatchResource,
 20	  WatchK8sResource,
 21	} from '@openshift-console/dynamic-plugin-sdk';
 22	import { getFieldId } from '../../pipelines-details/multi-column-field/utils';
 23	import { useFormikValidationFix } from '../../pipelines-details/multi-column-field/formik-validation-fix';
 24	import ResourceDropdown from '../../common/ResourceDropdown';
 25	
 26	interface MultipleResourceKeySelectorProps {
 27	  label: string;
 28	  resourceModel: K8sKind;
 29	  required?: boolean;
 30	  resourceNameField: string;
 31	  resourceKeysField: string;
 32	  addString?: string;
 33	}
 34	
 35	const MultipleResourceKeySelector: React.FC<
 36	  MultipleResourceKeySelectorProps
 37	> = ({
 38	  label,
 39	  resourceModel,
 40	  required,
 41	  resourceNameField,
 42	  resourceKeysField,
 43	  addString,
 44	}) => {
 45	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 46	  const [namespace] = useActiveNamespace();
 47	  const { setFieldValue, setFieldTouched } = useFormikContext<FormikValues>();
 48	  const [field, { touched, error }] = useField(resourceNameField);
 49	  const isValid = !(touched && error);
 50	  const fieldId = getFieldId(resourceNameField, 'res-dropdown');
 51	  const [keys, setKeys] = React.useState({});
 52	
 53	  useFormikValidationFix(field.value);
 54	
 55	  const resource: WatchK8sResource = React.useMemo(
 56	    () => ({
 57	      kind: resourceModel.kind,
 58	      isList: true,
 59	      namespace,
 60	      optional: true,
 61	    }),
 62	    [namespace, resourceModel.kind],
 63	  );
 64	
 65	  const [resources, loaded, loadError] = useK8sWatchResource(resource);
 66	
 67	  const autocompleteFilter = (strText, item): boolean =>
 68	    fuzzy(strText, item?.props?.name);
 69	
 70	  const generateKeys = (resourceName: string) => {
 71	    const selectedResource: K8sResourceKind = _.find(resources, (res) => {
 72	      return _.get(res, 'metadata.name') === resourceName;
 73	    });
 74	    const keyMap = selectedResource?.data ?? {};
 75	    const itemKeys = Object.keys(keyMap).reduce(
 76	      (acc, key) => ({ ...acc, [key]: key }),
 77	      {},
 78	    );
 79	    setKeys(itemKeys);
 80	  };
 81	
 82	  return (
 83	    <FormGroup
 84	      fieldId={fieldId}
 85	      label={label}
 86	      className="odc-multiple-key-selector"
 87	      isRequired={required}
 88	    >
 89	      <ResourceDropdown
 90	        resources={[
 91	          {
 92	            kind: resourceModel.kind,
 93	            loaded,
 94	            loadError,
 95	            data: resources as K8sResourceKind[],
 96	          },
 97	        ]}
 98	        loaded={loaded}
 99	        loadError={loadError}
100	        dataSelector={['metadata', 'name']}
101	        selectedKey={field.value}
102	        placeholder={t('Select a {{label}}', {
103	          label: t(resourceModel.labelKey),
104	        })}
105	        autocompleteFilter={autocompleteFilter}
106	        dropDownClassName={cx({ 'dropdown--full-width': true })}
107	        onChange={(value: string) => {
108	          setFieldValue(resourceKeysField, undefined);
109	          setFieldValue(resourceNameField, value);
110	          setFieldTouched(resourceNameField, true);
111	          generateKeys(value);
112	        }}
113	        showBadge
114	      />
115	      {field.value && !_.isEmpty(keys) && (
116	        <MultipleKeySelector
117	          name={resourceKeysField}
118	          keys={keys}
119	          addString={addString}
120	        />
121	      )}
122	
123	      {!isValid && (
124	        <FormHelperText>
125	          <HelperText>
126	            <HelperTextItem variant="error" icon={<RedExclamationCircleIcon />}>
127	              {error}
128	            </HelperTextItem>
129	          </HelperText>
130	        </FormHelperText>
131	      )}
132	    </FormGroup>
133	  );
134	};
135	
136	export default MultipleResourceKeySelector;

